// UI Elements
const linhagemSelect = document.getElementById('linhagem-select');
const quantidadeRange = document.getElementById('quantidade-range');
const rangeValue = document.getElementById('range-value');
const especificaRadios = document.getElementsByName('especifica');
const step4 = document.getElementById('step-4');
const nomeEntidadeInput = document.getElementById('nome-entidade');
const searchBtn = document.getElementById('search-btn-v2');
const formContainer = document.getElementById('form-container');
const loadingState = document.getElementById('loading-state');
const resultsSection = document.getElementById('results-section');
const lyricsGrid = document.getElementById('lyrics-grid');
const resultTitle = document.getElementById('result-title');
const backBtn = document.getElementById('back-btn');
const progressBar = document.querySelector('.progress-bar');

// Update range value display
quantidadeRange.addEventListener('input', () => {
    rangeValue.textContent = quantidadeRange.value;
});

// Show/Hide specific name input
especificaRadios.forEach(radio => {
    radio.addEventListener('change', () => {
        if (radio.value === 'sim') {
            step4.classList.remove('hidden');
        } else {
            step4.classList.add('hidden');
        }
    });
});

function normalizeText(text) {
    return text.toLowerCase()
        .normalize("NFD")
        .replace(/[\u0300-\u036f]/g, "")
        .replace(/\s+/g, '');
}

async function performSearch() {
    const linhagem = linhagemSelect.value;
    const quantidade = parseInt(quantidadeRange.value);
    const isEspecifica = document.querySelector('input[name="especifica"]:checked').value === 'sim';
    const nomeEspecifico = nomeEntidadeInput.value.toLowerCase().trim();

    // Show loading state
    formContainer.classList.add('hidden');
    loadingState.classList.remove('hidden');
    
    // Simulate "Internet Search" with progress bar
    for (let i = 0; i <= 100; i += 2) {
        progressBar.style.width = i + '%';
        await new Promise(r => setTimeout(r, 30));
    }

    // Logic to find points
    let points = [];
    const pool = database[linhagem] || [];

    if (isEspecifica && nomeEspecifico) {
        const normalizedTarget = normalizeText(nomeEspecifico);
        points = pool.filter(p => 
            normalizeText(p.title).includes(normalizedTarget) || 
            normalizeText(p.content).includes(normalizedTarget)
        );
        
        // If not enough points found for specific entity, add some general ones or show what we have
        if (points.length === 0) {
            alert(`Nenhum ponto específico para "${nomeEspecifico}" encontrado na linhagem ${linhagem}. Mostrando pontos gerais.`);
            points = shuffleArray([...pool]).slice(0, quantidade);
        } else {
            points = points.slice(0, quantidade);
        }
    } else {
        points = shuffleArray([...pool]).slice(0, quantidade);
    }

    displayResults(points, linhagem, isEspecifica ? nomeEspecifico : 'Aleatório');
}

function shuffleArray(array) {
    for (let i = array.length - 1; i > 0; i--) {
        const j = Math.floor(Math.random() * (i + 1));
        [array[i], array[j]] = [array[j], array[i]];
    }
    return array;
}

function displayResults(points, linhagem, subTitle) {
    loadingState.classList.add('hidden');
    resultsSection.classList.remove('hidden');
    
    resultTitle.textContent = `${linhagem.charAt(0).toUpperCase() + linhagem.slice(1)} - ${subTitle}`;
    lyricsGrid.innerHTML = '';

    if (points.length === 0) {
        lyricsGrid.innerHTML = '<p class="no-results">Nenhum ponto encontrado para esta busca.</p>';
        return;
    }

    points.forEach(ponto => {
        const card = document.createElement('div');
        card.className = 'lyric-card';
        card.innerHTML = `
            <h4 class="lyric-title">${ponto.title}</h4>
            <p class="lyric-content">${ponto.content}</p>
            <button class="copy-btn" onclick="copyLyric(this)">Copiar Letra</button>
        `;
        lyricsGrid.appendChild(card);
    });
}

function copyLyric(btn) {
    const content = btn.parentElement.querySelector('.lyric-content').textContent;
    navigator.clipboard.writeText(content).then(() => {
        const originalText = btn.textContent;
        btn.textContent = 'Copiado!';
        setTimeout(() => btn.textContent = originalText, 2000);
    });
}

function resetForm() {
    resultsSection.classList.add('hidden');
    formContainer.classList.remove('hidden');
    progressBar.style.width = '0%';
}

searchBtn.addEventListener('click', performSearch);
backBtn.addEventListener('click', resetForm);

window.copyLyric = copyLyric;
